export const DICTS = { DE, ES, FR };

/* BCP-47 tags for the browser TTS voice, per UI language. */
export const TTS_LANG = { EN: 'en-US', DE: 'de-DE', ES: 'es-ES', FR: 'fr-FR' };

/* Deep-localize a mission or call scenario. Strings found in the language
   dictionary are swapped; everything else (numbers, ids, tool signatures,
   spark data) passes through untouched. */
export function locDemo(node, lang) {
  if (lang === 'EN') return node;
  const t = DICTS[lang];
  if (!t) return node;
  const walk = (v) => {
    if (typeof v === 'string') return t[v] ?? v;
    if (Array.isArray(v)) return v.map(walk);
    if (v && typeof v === 'object') {
      const o = {};
      for (const k of Object.keys(v)) o[k] = k === 'call' ? v[k] : walk(v[k]);
      return o;
    }
    return v;
  };
  return walk(node);
}
